async function convertWorkflowOrchestratorPage() {
  try {
    console.log('🔄 Converting Workflow Orchestrator page to builder format...');

    // Find the workflow orchestrator page
    const page = await prisma.page.findFirst({
      where: {
        id: 'cmivhudw10000ucj51prdaxnl'
      }
    });

    if (!page) {
      console.error('❌ Workflow Orchestrator page not found');
      return;
    }

    console.log(`📄 Found page: ${page.title} (ID: ${page.id})`);

    // Update the page with builder data
    await prisma.page.update({
      where: { id: page.id },
      data: {
        builderData: JSON.stringify({ sections: workflowOrchestratorSections }),
        isBuilderPage: true,
        builderVersion: '1.0',
        updatedAt: new Date(),
      },
    });

    console.log(`✅ Successfully converted page with ${workflowOrchestratorSections.length} sections`);
    console.log('📋 Sections added:');
    workflowOrchestratorSections.forEach((section, index) => {
      console.log(`   ${index + 1}. ${section.type} - ${section.data.title || section.id}`);
    });

  } catch (error) {
    console.error('❌ Error converting page:', error);
  } finally {
    await prisma.$disconnect();
  }
}

// Run the conversion
convertWorkflowOrchestratorPage();